// Node: Detect Malveillance (GENERAL)
// Output: ONE item only
// - has_alert = true  => branche "alert email"
// - has_alert = false => branche "Respond to Webhook"

function n(x) {
  const v = Number(x);
  return Number.isFinite(v) ? v : null;
}

function pickFirstAlertLike(obj) {
  // accepte plusieurs formats possibles
  if (!obj) return null;
  if (Array.isArray(obj.alerts) && obj.alerts.length) return obj.alerts[0];
  if (Array.isArray(obj.anomalies) && obj.anomalies.length) return obj.anomalies[0];
  if (obj.alert && typeof obj.alert === "object") return obj.alert;
  return null;
}

function maxSeverity(a, b) {
  const r = { INFO: 0, WARNING: 1, CRITICAL: 2 };
  const A = (a || "INFO").toUpperCase();
  const B = (b || "INFO").toUpperCase();
  return (r[B] ?? 0) > (r[A] ?? 0) ? B : A;
}

// 1) agrège tous les items (important pour éviter double mail)
let best = null;
let severity = "INFO";

for (const it of items) {
  const j = it.json || {};

  // tu peux produire has_alert en amont, on le respecte
  const upstreamHas = j.has_alert === true || j.has_alert === "true";

  // sinon on tente de détecter via champs connus
  const a = pickFirstAlertLike(j);
  const ae = n(a?.ae_reconstruction ?? j.ae_reconstruction);
  const sil = n(a?.silhouette ?? j.silhouette);
  const score = n(a?.score ?? j.score);

  // Heuristique générique (modifie les seuils si besoin)
  const TH = {
    ae_high: 0.70,
    silhouette_low: 0.10,
    score_low: -0.20,
  };

  const heurHas =
    (ae !== null && ae >= TH.ae_high) ||
    (sil !== null && sil <= TH.silhouette_low) ||
    (score !== null && score <= TH.score_low) ||
    (String(j.pipeline_status || "").includes("KO"));

  const has_alert = upstreamHas || heurHas;

  if (has_alert) {
    const sev = (a?.severity || j.severity || "CRITICAL").toUpperCase();
    severity = maxSeverity(severity, sev);

    // on garde la meilleure alerte (ici: la plus sévère)
    if (!best) best = { it: j, a, ae, sil, score, sev };
    else if (maxSeverity(best.sev, sev) === sev) best = { it: j, a, ae, sil, score, sev };
  }
}

// 2) construire l’output unique
const now = new Date().toISOString();

if (!best) {
