    has_alert: true,
    severity,
    alerts: [{
      symbol: a.symbol ?? j.symbol ?? j.ticker ?? "-",
      run_id: a.run_id ?? j.run_id ?? j.mlflow_run_id ?? "-",
      ae_reconstruction: best.ae,
