  }
}];

function findBars(j) {
  return (j.bars || j.candles || j.data || j.ohlcv || []);
}

function pickOpen(b) {
  if (!b) return null;
  if (typeof b.open === "number") return b.open;
  if (typeof b.o === "number") return b.o;
  return null;
}

function pickClose(b) {
  if (!b) return null;
  if (typeof b.close === "number") return b.close;
  if (typeof b.c === "number") return b.c;
  if (typeof b.adjClose === "number") return b.adjClose;
  if (typeof b.adj_close === "number") return b.adj_close;
  return null;
}

return items.map((it) => {
  const j = it.json || {};
  const symbol = j.symbol || j.ticker || "UNKNOWN";
  const bars = findBars(j);

  // Garde uniquement les bougies qui ont au moins un close valide
  const valid = Array.isArray(bars)
    ? bars.filter(b => b && (typeof b.close === "number" || typeof b.c === "number"))
    : [];

  if (valid.length < 2) {
    return { json: { indicator: symbol, open_today: "", close_previous_day: "", warning: j.warning || "NO_2_BARS" } };
  }

  const prev = valid[valid.length - 2];
  const today = valid[valid.length - 1];

  return {
