<div style="font-family: Arial, Helvetica, sans-serif; color:#0f172a; background:#f8fafc; padding:24px; border-radius:14px;">
  <div style="max-width:760px; margin:0 auto; background:#ffffff; border:1px solid #e2e8f0; border-radius:16px; overflow:hidden;">
    <div style="padding:18px 22px; background:linear-gradient(90deg,#0f172a,#1e293b); color:#fff;">
      <div style="font-size:18px; font-weight:700;">📈 StormCopilot – Daily Open/Close</div>
      <div style="font-size:12px; opacity:0.85; margin-top:4px;">
        Jour de marché : <b>${market_day}</b> • Open du jour vs Close de la veille • Gap %
      </div>
    </div>

    <div style="padding:18px 22px;">
      <p style="margin:0 0 12px 0; font-size:14px; line-height:1.6;">Bonjour,</p>
      <p style="margin:0 0 14px 0; font-size:14px; line-height:1.6;">
        Veuillez trouver en pièce jointe le fichier <b>CSV</b> (3 colonnes) pour les indicateurs disponibles.
      </p>

      <div style="margin:16px 0 10px 0; padding:12px 14px; border:1px solid #e2e8f0; border-radius:12px; background:#f1f5f9;">
        <div style="font-size:13px; font-weight:700; margin-bottom:6px;">Aperçu rapide</div>
        <div style="font-size:12px; color:#334155;">(${rows.length} indicateur(s) dans ce run) • Pièce jointe : <b>${filename}</b></div>
      </div>

      <table cellpadding="0" cellspacing="0" style="width:100%; border-collapse:separate; border-spacing:0; border:1px solid #e2e8f0; border-radius:12px; overflow:hidden;">
        <thead>
          <tr style="background:#0ea5e9; color:#fff;">
            <th style="text-align:left; padding:10px 12px; font-size:13px;">Indicateur</th>
            <th style="text-align:right; padding:10px 12px; font-size:13px;">Open (J)</th>
            <th style="text-align:right; padding:10px 12px; font-size:13px;">Close (J-1)</th>
            <th style="text-align:right; padding:10px 12px; font-size:13px;">Gap %</th>
          </tr>
        </thead>
        <tbody>
          ${htmlRows}
        </tbody>
      </table>

      <div style="margin-top:16px; padding-top:12px; border-top:1px solid #e2e8f0; font-size:13px; color:#334155; line-height:1.6;">
        Cordialement,<br/><b>StormCopilot</b>
      </div>

      <div style="margin-top:10px; font-size:11px; color:#64748b;">
        Email automatique • ${market_day}
      </div>
    </div>
  </div>
</div>
`;

return [{
  json: { filename, html, subject, market_day },
  binary: {
    data: {
      data: buffer.toString("base64"),
      mimeType: "text/csv",
      fileName: filename
    }
  }
}];

// n8n Function node: Add Trace / Audit Stamp (final)
// Place: after "Build Human Text Daily" and before "Quality Gate" + "Generate Daily PDF"

const d = items[0]?.json || {};
const now = new Date().toISOString();

// ---------- helpers
function numOr(x, def) {
  const v = Number(x);
  return Number.isFinite(v) ? v : def;
}
function strOr(x, def = "") {
  const s = (x === null || x === undefined) ? "" : String(x);
  return s.trim() ? s : def;
}
function safeLen(arr) {
  return Array.isArray(arr) ? arr.length : 0;
}
function objSize(o) {
  return (o && typeof o === "object" && !Array.isArray(o)) ? Object.keys(o).length : 0;
}

// ---------- detect pipeline
const isDailyFull = !!d.tech_radar || !!d.market_ai_summary;
const isMLOps =
  (Array.isArray(d.mlops_champions_rows) && d.mlops_champions_rows.length > 0) ||
  (Array.isArray(d.mlops_compare_rows) && d.mlops_compare_rows.length > 0) ||
  (d.raw_champions && Object.keys(d.raw_champions).length > 0) ||
  !!d.mlops_kpis;

const pipeline = isDailyFull ? "daily_full" : (isMLOps ? "mlops_daily" : "unknown");

// ---------- run id
const runId =
  d.run_id ||
  d.trace?.run_id ||
  `run_${Date.now().toString(36)}_${Math.random().toString(16).slice(2, 8)}`;

// ---------- base trace
d.trace = {
  run_id: runId,
  generated_at: d.generated_at || now,
  workflow: strOr(d.workflow, "StormCopilot"),
  pipeline,

  // Quality / retry (may be filled by Quality Gate later)
  quality_ok: (typeof d.quality_ok === "boolean") ? d.quality_ok : true,
  quality_level: strOr(d.quality_level, ""),
  quality_reason: strOr(d.quality_reason, ""),
  retry_count: numOr(d.retry_count, 0),

  // common
  severity: d.severity ?? d.global_severity ?? ""
};

// ---------- pipeline-specific stats (NO NULLS)
if (pipeline === "daily_full") {
  const tech = d.tech_radar || {};
  const met = tech.metrics || {};

  d.trace.tech_sources_total = numOr(met.sources_total, 0);
  d.trace.tech_sources_ok    = numOr(met.sources_ok, 0);
  d.trace.tech_hot          = numOr(met.hot, 0);
  d.trace.tech_trending     = numOr(met.trending, 0);
  d.trace.tech_fresh        = numOr(met.fresh, 0);

  const m = d.market_ai_summary || {};
  d.trace.market_assets = numOr(m.nb_assets, 0);
  d.trace.market_rows   = safeLen(d.market_ai_rows);

} else if (pipeline === "mlops_daily") {
  const k = d.mlops_kpis || {};
  const rawChamp = d.raw_champions || {};
  const rows = d.mlops_compare_rows || d.mlops_champions_rows || [];

  d.trace.mlops_pipeline_status = strOr(k.pipeline_status, "—");
  d.trace.mlops_nb_symbols_ok   = numOr(k.nb_symbols_ok, objSize(rawChamp));
  d.trace.mlops_nb_requested    = numOr(k.nb_symbols_requested, 0);
  d.trace.champions_count       = objSize(rawChamp);
  d.trace.champions_rows_count  = safeLen(rows);

  d.trace.drift_avg = numOr(k.drift_avg, 0);
  d.trace.drift_max = numOr(k.drift_max, 0);
  d.trace.retrain_recommended = !!k.retrain_recommended;

  // Keep old tech fields out (or set to 0 if you want)
  d.trace.tech_sources_total = 0;
  d.trace.tech_sources_ok    = 0;
  d.trace.tech_hot           = 0;
  d.trace.tech_trending      = 0;
  d.trace.tech_fresh         = 0;
}

// write back
items[0].json = d;
return items;

// n8n Function node: Quality Gate (Daily Full + MLOps)
// Place: after "Add Trace / Audit Stamp" and before "Generate Daily PDF"

const d = items[0]?.json || {};
d.trace = d.trace || {};

const reasons = [];
let ok = true;

// Detect pipeline (prefer trace.pipeline)
const pipeline =
  d.trace.pipeline ||
  (d.tech_radar || d.market_ai_summary ? "daily_full" : "mlops_daily");

// --------------------
// Helpers
function hasNonEmptyObject(x) {
  return x && typeof x === "object" && !Array.isArray(x) && Object.keys(x).length > 0;
}
function n(x) {
  const v = Number(x);
  return Number.isFinite(v) ? v : null;
}
// --------------------

// ====================
// Case 1: DAILY FULL
// ====================
if (pipeline === "daily_full") {
  // Tech
  const tech = d.tech_radar || {};
  const met = tech.metrics || {};
  const sourcesTotal = n(met.sources_total);
  const sourcesOk = n(met.sources_ok);

  if (!(sourcesTotal !== null && sourcesOk !== null && sourcesOk > 0 && sourcesOk <= sourcesTotal)) {
    ok = false;
    reasons.push("tech_missing_or_incomplete");
  }

  // Market
  const m = d.market_ai_summary || {};
  const nbAssets = n(m.nb_assets);
  if (!(nbAssets !== null && nbAssets > 0)) {
    ok = false;
    reasons.push("market_missing_or_incomplete");
  }

  // Optional: require some rows
  const rows = Array.isArray(d.market_ai_rows) ? d.market_ai_rows.length : 0;
  if (rows === 0) {
    ok = false;
    reasons.push("market_rows_empty");
  }
}

// ====================
// Case 2: MLOPS DAILY
// ====================
else if (pipeline === "mlops_daily") {
  const k = d.mlops_kpis || {};
  const decision = d.mlops_decision || {};
  const rawChamp = d.raw_champions || {};

  // pipeline status
  if (String(k.pipeline_status || "") !== "✅ OK") {
    ok = false;
    reasons.push("mlops_pipeline_not_ok");
  }

  // must have champions
  if (!hasNonEmptyObject(rawChamp)) {
    ok = false;
    reasons.push("mlops_champions_missing");
  }

  // must have decision explanation
  if (!String(decision.explanation || "").trim()) {
    ok = false;
    reasons.push("mlops_decision_missing");
  }

  // optional: compare table present (not mandatory)
  const cmpRows = Array.isArray(d.mlops_compare_rows) ? d.mlops_compare_rows.length : 0;
  if (cmpRows === 0) {
    reasons.push("mlops_compare_rows_empty");
    // (on ne fail pas pour ça, c'est juste un warning)
  }
}

// Unknown pipeline -> soft fail
else {
  ok = false;
  reasons.push("pipeline_unknown");
}

// ---- set quality
const level = ok ? "PASS" : "FAIL";
const reasonStr = reasons.join(",");

d.quality_ok = ok;
d.quality_level = level;
d.quality_reason = reasonStr;

d.trace.quality_ok = ok;
d.trace.quality_level = level;
d.trace.quality_reason = reasonStr;

items[0].json = d;
return items;

// n8n Code node: Build Tech Digest (Top + Sources + Themes)
// Place: after "Normalize Tech Metrics" and before "Tech Clean & Rank"

const tech = items[0]?.json || {};
const raw = tech._raw || {};
const list = Array.isArray(raw.items) ? raw.items : (Array.isArray(raw.data?.items) ? raw.data.items : []);

function clean(s) {
  return String(s || "")
    .replace(/\s+/g, " ")
    .replace(/[\u0000-\u001F]+/g, "")
    .trim();
}
function clip(s, n=110) {
  s = clean(s);
  return s.length > n ? (s.slice(0, n - 1) + "…") : s;
}

// --- Split by label
const isHot = (x) => String(x.rank_label || "").toLowerCase().includes("hot");
const isTrending = (x) => String(x.rank_label || "").toLowerCase().includes("trending");
const isFresh = (x) => String(x.rank_label || "").toLowerCase().includes("fresh");

const hot = list.filter(isHot);
const trending = list.filter(isTrending);

// --- Top lists
const topHot = (hot.length ? hot : list).slice(0, 5).map(x => ({
  source: clean(x.source_name || x.source || "Source"),
  title: clip(x.title || x.headline || x.short_summary || x.tw_summary_2_sent || x.summary || x.url || "—", 120),
  label: "Hot",
  url: x.url || ""
}));

const topTrending = (trending.length ? trending : list).slice(0, 5).map(x => ({
  source: clean(x.source_name || x.source || "Source"),
  title: clip(x.title || x.headline || x.short_summary || x.tw_summary_2_sent || x.summary || x.url || "—", 120),
  label: "Trending",
  url: x.url || ""
}));

// --- Top Sources
const srcCount = {};
for (const x of list) {
  const s = clean(x.source_name || x.source || "Source");
  srcCount[s] = (srcCount[s] || 0) + 1;
}
const topSources = Object.entries(srcCount)
  .sort((a,b) => b[1]-a[1])
  .slice(0, 6)
  .map(([source, count]) => ({ source, count }));

// --- Themes (keywords)
const stop = new Set(["the","and","for","with","from","that","this","you","your","are","was","were","to","of","in","on","a","an","is","it","as","by","at","or","be","how","what","why","when","data","ai"]);
const bag = {};
for (const x of list.slice(0, 25)) {
  const text = clean((x.title || "") + " " + (x.short_summary || x.tw_summary_2_sent || x.summary || ""));
  for (const w of text.toLowerCase().split(/[^a-z0-9]+/g)) {
    if (!w || w.length < 4) continue;
    if (stop.has(w)) continue;
    bag[w] = (bag[w] || 0) + 1;
  }
}
const themes = Object.entries(bag).sort((a,b)=>b[1]-a[1]).slice(0, 8).map(([k,v]) => ({ keyword:k, count:v }));

// --- Markdown digest (PDF/mail)
function mdTable(rows) {
  let md = `| Source | Label | Titre |\n|---|---|---|\n`;
  for (const r of rows) md += `| ${clip(r.source, 30)} | ${r.label} | ${clip(r.title, 95)} |\n`;
  return md;
}

let digestMd = "";
digestMd += `### 🔥 Top Hot (5)\n${topHot.length ? mdTable(topHot) : "_Aucun item._"}\n\n`;
digestMd += `### 📈 Top Trending (5)\n${topTrending.length ? mdTable(topTrending) : "_Aucun item._"}\n\n`;

if (topSources.length) {
  digestMd += `### 🧩 Sources dominantes\n| Source | # |\n|---|---:|\n`;
  for (const s of topSources) digestMd += `| ${clip(s.source, 40)} | ${s.count} |\n`;
  digestMd += `\n`;
}
if (themes.length) {
  digestMd += `### 🏷️ Thèmes du jour\n` + themes.map(t => `- ${t.keyword} (${t.count})`).join("\n") + `\n`;
}

return [{
  json: {
    ...tech,
    headline: clip(tech.headline || "Veille Tech", 110),
    tech_digest_md: digestMd,
    tech_top_hot: topHot,
    tech_top_trending: topTrending,
    tech_top_sources: topSources,
    tech_themes: themes,
  }
}];

// Tech Clean & Rank (FINAL, frontend + PDF ready)

const tech = items[0]?.json || {};
const list = Array.isArray(tech._raw?.items) ? tech._raw.items : [];

function clean(s){ return String(s||"").replace(/\s+/g," ").trim(); }
function clip(s,n=110){ s=clean(s); return s.length>n ? s.slice(0,n-1)+"…" : s; }

function score100(x){
  const v = Number(x.score_24h ?? x.score ?? 0);
  if (!Number.isFinite(v)) return 0;
  return Math.round(v <= 1 ? v * 100 : v);
}

function faviconOf(x){
  if (x.favicon_url) return x.favicon_url;
  try {
    const h = new URL(x.url).hostname;
    return `https://www.google.com/s2/favicons?sz=64&domain=${h}`;
  } catch {
    return "";
  }
}

// ---- FILTER TRENDING 24H (⭐ Trending uniquement)
const trending24h = list
  .filter(x => String(x.rank_label || "").includes("Trending"))
  .sort((a,b) => score100(b) - score100(a))
  .slice(0, 6)
  .map(x => ({
    source: clean(x.source_name),
    score: score100(x),
    favicon: faviconOf(x),
    url: x.url || ""
  }));

// ---- PDF / MAIL markdown
let trendingMd = "### 📈 Top Trending (24h)\n";
if (!trending24h.length) {
  trendingMd += "_Aucun item._\n\n";
} else {
  trendingMd += `| Source | Score |\n|---|---:|\n`;
  for (const t of trending24h) {
    trendingMd += `| ${clip(t.source,40)} | ${t.score}/100 |\n`;
  }
  trendingMd += "\n";
}

// ---- RETURN
return [{
  json: {
    ...tech,
    top_trending_24h: trending24h,      // ✅ frontend
    tech_digest_md: trendingMd + (tech.tech_digest_md || "")
  }
}];

const d = items[0]?.json || {};

return [{
  json: {
    ...d,
    has_alert: true,
    severity: "CRITICAL",
    alerts: [{
      symbol: "BNP.PA",
      run_id: "TEST_RUN_ID_123",
      ae_reconstruction: 0.99,
      silhouette: 0.05,
      score: -2.0,
      severity: "CRITICAL"
    }],
    generated_at: new Date().toISOString()
  }
}];
